mapper.select:
SELECT rp.id, rp.risk_name, rp.risk_code, rp.town_street_name, rp.address, rp.prevent_status, org.organization_name, IFNULL(MAX(dip.device_type), '') AS device_type, IFNULL(MAX(dip.plan_quantity), 0) AS plan_quantity, IFNULL(MAX(dip.unit), '') AS unit, IFNULL(MAX(dip.plan_install_start_date), '') AS plan_install_start_date, IFNULL(MAX(dip.plan_install_end_date), '') AS plan_install_end_date, IFNULL(MAX(dip.plan_install_start_date), '') AS plan_install_date FROM rp_risk_point rp LEFT JOIN tbl_organization org ON rp.org_id = org.id AND org.deleted = 0 LEFT JOIN rp_device_install_plan dip ON rp.id = dip.risk_id AND dip.deleted = 0 WHERE rp.deleted = 0
AND rp.risk_name LIKE CONCAT('%', #{riskName}, '%')
AND rp.risk_code = #{riskCode}
AND org.organization_name = #{organizationName}
AND dip.plan_install_start_date >= #{planInstallStartDate}
AND dip.plan_install_end_date <= #{planInstallEndDate}
GROUP BY rp.id, rp.risk_name, rp.risk_code, rp.town_street_name, rp.address, rp.prevent_status, org.organization_name ORDER BY rp.id DESC
